class Solution:
    def numRescueBoats(self, people, limit):
        from collections import deque
        q = deque(sorted(people))
        boats = 0
        while q:
            heavy = q.pop()
            boats += 1
            if q and q[0] + heavy <= limit:
                q.popleft()
        return boats

